\begin{proof}[Proof of Theorem~\ref{thm:coordcover}]
Write $\lambda=(\lambda_1,\dots,\lambda_r)$. For each $i\in[r]$, let $\Gamma_i=(G,\lambda_i)$. Apply Theorem~\ref{thm:onecoord} to every $\Gamma_i$ obtaining $(S_i,F_i)$. Define $S:=\bigcup_{i=1}^r S_i$ and $F:=\bigcap_{i=1}^r F_i$.
\noindent\emph{Property (ii).}
Fix a coordinate $i$. Since $S_i \subseteq S$ and $F \subseteq F_i$, the graph $(G-F)[S]$ is balanced in coordinate $i$ because it contains $(G-F_i)[S_i]$. By Lemma~\ref{lem:coordinatewise}, $(G-F)[S]$ is balanced.
\end{proof}

